import axios from 'axios';
import React, { useState, useRef } from 'react';
import { Button, Box, Typography, List, ListItem, ListItemText, LinearProgress, Alert } from '@mui/material'; // Material-UI bileşenlerini ekledik

function FileUploadPage({ folderId, onUploadSuccess }) { // onUploadSuccess prop'unu ekledik
  const [files, setFiles] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [uploadError, setUploadError] = useState('');
  const fileInputRef = useRef(null);

  const handleFileChange = (event) => {
    setUploadError(''); // Yeni dosya seçildiğinde hatayı temizle
    const selectedFiles = Array.from(event.target.files);
    setFiles((prevFiles) => [...prevFiles, ...selectedFiles]);
  };

  const handleUpload = async () => {
    if (files.length === 0) {
      setUploadError('Lütfen yüklenecek dosya seçin.');
      return;
    }

    const formData = new FormData();

    Array.from(files).forEach(file => {
      formData.append('files', file);
    });

    setUploading(true);
    setUploadError('');
    try {
      // folderId null ise, boş string gönderilir (kök dizin için)
      const uploadUrl = `/api/files/upload-multiple/${folderId ?? ''}`;
      const response = await axios.post(uploadUrl, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      alert('Dosyalar başarıyla yüklendi!');
      console.log(response.data);
      setFiles([]);
      if (fileInputRef.current) {
        fileInputRef.current.value = null; // Inputu sıfırla
      }
      onUploadSuccess?.(); // Yükleme başarılı olduğunda callback'i çağır

    } catch (error) {
      if (error.response) {
        const { status, data } = error.response;

        if (status === 400 && data.failedFileNames) {
          const failedList = data.failedFileNames.join('\n');
          setUploadError('Bazı dosyalar zaten var olduğu için yüklenemedi:\n' + failedList);
        } else if (data.message) {
          setUploadError(data.message);
        } else {
          setUploadError('Yükleme sırasında bir hata oluştu: ' + status);
        }
      } else {
        setUploadError('Sunucuya ulaşılamıyor.');
      }
    } finally {
      setUploading(false);
    }
  };

  return (
    <Box sx={{ p: 2 }}>
      <Typography variant="h6" gutterBottom>Dosya Yükle</Typography>

      {folderId && (
        <Typography variant="body2" color="textSecondary" sx={{ mb: 2 }}>
          Seçili Klasör ID: **{folderId}**
        </Typography>
      )}

      <Box sx={{ mb: 3 }}>
        <input
          type="file"
          multiple
          onChange={handleFileChange}
          ref={fileInputRef}
          style={{ display: 'block', marginBottom: '16px' }}
        />
        <Button
          variant="contained"
          component="span" // input'u tetiklemek için span olarak ayarla
          sx={{ mr: 1 }}
        >
          Dosyaları Seç
        </Button>
      </Box>

      {files.length > 0 && (
        <Box sx={{ mb: 3 }}>
          <Typography variant="subtitle1" gutterBottom>Seçilen Dosyalar:</Typography>
          <List dense>
            {Array.from(files).map((file, index) => (
              <ListItem key={index} disablePadding>
                <ListItemText
                  primary={file.name}
                  secondary={`${(file.size / 1024).toFixed(1)} KB`}
                />
              </ListItem>
            ))}
          </List>
        </Box>
      )}

      {uploadError && (
        <Alert severity="error" sx={{ mb: 2 }}>
          {uploadError}
        </Alert>
      )}

      <Button
        variant="contained"
        color="primary"
        onClick={handleUpload}
        disabled={uploading || files.length === 0}
      >
        {uploading ? <LinearProgress sx={{ width: '100%' }} /> : 'Dosyaları Yükle'}
      </Button>
    </Box>
  );

}

export default FileUploadPage;
